                id, 
                JSON.stringify({ notes: notes || '' }),
                `Salary Disbursement for ${record.staffName} (${record.month})`
            );
        }
    });

    try {
        tx();
        res.json({ success: true });
    } catch(e) {
        console.error(e);
        res.status(500).json({ error: e.message });
    }
};

